<?php use App\Helpers\Csrf; use App\Helpers\Sanitizer; use App\Helpers\Url; ?>
<main class="container"><section class="module-hero"><div><span class="eyebrow">Catálogo</span><h1>Tipos de partes</h1><p>Administra las categorías de piezas: motores, puertas, vidrios, retrovisores y más.</p></div><div class="action-row"><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/dashboard')) ?>">Panel</a><a class="btn" href="<?= Sanitizer::html(Url::ruta('/partes/crear')) ?>">Nueva parte</a></div></section><section class="card"><form class="filter-form" method="GET"><div class="form-group"><label>Buscar</label><input name="buscar" value="<?= Sanitizer::html($busqueda ?? '') ?>" placeholder="Nombre de parte"></div><div class="form-group"><label>Estado</label><select name="estado"><option value="">Todos</option><option value="1" <?= ($estado ?? '')==='1'?'selected':'' ?>>Activos</option><option value="0" <?= ($estado ?? '')==='0'?'selected':'' ?>>Inactivos</option></select></div><div class="form-actions compact"><button class="btn">Filtrar</button><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/partes')) ?>">Limpiar</a></div></form></section><section class="card table-wrapper"><table><thead><tr><th>Nombre</th><th>Descripción</th><th>Estado</th><th>Acciones</th></tr></thead><tbody><?php if(empty($partes)): ?><tr><td colspan="4" class="empty-state">No hay partes registradas.</td></tr><?php endif; ?><?php foreach($partes as $parte): ?><tr><td><?= Sanitizer::html($parte['nombre_parte']) ?></td><td><?= Sanitizer::html($parte['descripcion'] ?? '') ?></td><td><?= (int)$parte['activo']===1?'<span class="badge badge-success">Activo</span>':'<span class="badge badge-danger">Inactivo</span>' ?></td><td class="acciones-tabla"><a class="btn btn-mini btn-secundario" href="<?= Sanitizer::html(Url::ruta('/partes/editar/'.$parte['id_parte'])) ?>">Editar</a><form method="POST" action="<?= Sanitizer::html(Url::ruta('/partes/estado/'.$parte['id_parte'])) ?>" data-confirm="¿Cambiar estado de la parte?"><?= Csrf::campo() ?><input type="hidden" name="activo" value="<?= (int)$parte['activo']===1?0:1 ?>"><button class="btn btn-mini <?= (int)$parte['activo']===1?'btn-danger':'' ?>" type="submit"><?= (int)$parte['activo']===1?'Desactivar':'Activar' ?></button></form></td></tr><?php endforeach; ?></tbody></table></section></main>
